pub const WRAM_END:                 u16 = 0xDFFF;
pub const ECHO_RAM_BASE:            u16 = 0xE000;
pub const ECHO_RAM_END:             u16 = 0xFDFF;
pub const OAM_BASE:                 u16 = 0xFE00;
pub const OAM_END:                  u16 = 0xFE9F;
pub const IO_BASE:                  u16 = 0xFF00;
